//! Pneuma TTS smoke — end-to-end text → wav round-trip.
//!
//! Loads two `.knot` files (acoustic + vocoder), tokenizes text into phoneme
//! IDs, runs the acoustic model to produce a mel-spectrogram, runs the vocoder
//! to produce f32 PCM, and writes a 16-bit mono WAV. Mirrors the structure of
//! the STT smoke binary [`pneuma-smoke`] for consistency.
//!
//! Usage:
//!   cargo run --release --bin pneuma-tts-smoke -- \
//!     /tmp/piper-amy.knot \
//!     /tmp/hifigan.knot \
//!     "the quick brown fox" \
//!     /tmp/piper-amy-out.wav
//!
//! Optional pre-tokenized phoneme override (skips the built-in heuristic G2P):
//!   cargo run --release --bin pneuma-tts-smoke -- \
//!     ... \
//!     "the quick brown fox" \
//!     /tmp/out.wav \
//!     --phonemes 12,5,7,8,1,5,9,11,1,3,4,5
//!
//! The full TS phonemizer (`distributed-inference-host/src/phonemizer.ts`)
//! covers a richer ruleset for host-driven pipelines; this binary keeps a
//! tiny built-in fallback so it stands alone for end-to-end smoke testing.

use std::env;
use std::fs;
use std::io::Write;
use std::sync::Arc;
use std::time::Instant;

use distributed_inference::loader::{
    parse_knot_codec, read_knot_metadata, KnotCodec, KnotWeights, WeightBackend,
};
use distributed_inference::model_pneuma_tts_acoustic::{
    parse_tts_config, TtsAcousticModel, TtsConfig,
};
use distributed_inference::model_pneuma_tts_vocoder::{
    parse_vocoder_config, HiFiGANVocoder, VocoderConfig,
};

// ─────────────────────────────────────────────────────────────────────────────
// Built-in trivial G2P (mirror of phonemizer.ts inventory at the lowest tier)
// ─────────────────────────────────────────────────────────────────────────────
//
// IDs MUST match the inventory in `distributed-inference-host/src/phonemizer.ts`
// (PHONEMES array). Keep these two in sync. The Rust side only uses the bare
// minimum needed to convert "the quick brown fox" into something the acoustic
// model can chew on; the TS side is the canonical, richer phonemizer.

const ID_PAUSE: u32 = 1;

/// Minimal letter-level G2P. Maps each lowercase letter to a single phoneme ID
/// from the canonical ARPAbet-style inventory; sufficient for smoke testing.
fn letter_to_phoneme_id(c: char) -> Option<u32> {
    Some(match c {
        'a' => 5,  // AH
        'b' => 19, // B
        'c' => 27, // K
        'd' => 21, // D
        'e' => 9,  // EH
        'f' => 23, // F
        'g' => 24, // G
        'h' => 25, // HH
        'i' => 12, // IH
        'j' => 26, // JH
        'k' => 27, // K
        'l' => 28, // L
        'm' => 29, // M
        'n' => 30, // N
        'o' => 14, // OW
        'p' => 32, // P
        'q' => 27, // K
        'r' => 33, // R
        's' => 34, // S
        't' => 36, // T
        'u' => 16, // UH
        'v' => 38, // V
        'w' => 39, // W
        'x' => 34, // S
        'y' => 40, // Y
        'z' => 41, // Z
        _ => return None,
    })
}

/// Tokenize text into phoneme IDs using the per-letter heuristic above.
fn text_to_phoneme_ids_trivial(text: &str) -> Vec<u32> {
    let mut out = Vec::with_capacity(text.len());
    let mut pending_boundary = false;
    for ch in text.to_lowercase().chars() {
        if ch.is_ascii_alphabetic() {
            if pending_boundary && !out.is_empty() {
                out.push(ID_PAUSE);
            }
            pending_boundary = false;
            if let Some(id) = letter_to_phoneme_id(ch) {
                out.push(id);
            }
        } else {
            pending_boundary = true;
        }
    }
    out
}

// ─────────────────────────────────────────────────────────────────────────────
// ─────────────────────────────────────────────────────────────────────────────
// WAV writer (16-bit PCM, mono)
// ─────────────────────────────────────────────────────────────────────────────

/// Write a mono 16-bit PCM WAV file. f32 samples are clipped to [-1, 1] and
/// scaled to int16. Inline `std::io::Write` so we don't drag in a `wav` crate.
fn write_wav_pcm16(path: &str, samples: &[f32], sample_rate: u32) -> Result<(), String> {
    let n_samples = samples.len() as u32;
    let bytes_per_sample = 2u32; // 16-bit
    let n_channels = 1u32;
    let byte_rate = sample_rate * n_channels * bytes_per_sample;
    let block_align = (n_channels * bytes_per_sample) as u16;
    let data_size = n_samples * bytes_per_sample;
    let chunk_size = 36 + data_size; // RIFF chunk size

    let mut buf: Vec<u8> = Vec::with_capacity(44 + data_size as usize);
    // RIFF header
    buf.extend_from_slice(b"RIFF");
    buf.extend_from_slice(&chunk_size.to_le_bytes());
    buf.extend_from_slice(b"WAVE");
    // fmt subchunk
    buf.extend_from_slice(b"fmt ");
    buf.extend_from_slice(&16u32.to_le_bytes()); // PCM fmt subchunk size
    buf.extend_from_slice(&1u16.to_le_bytes()); // audio format = PCM
    buf.extend_from_slice(&(n_channels as u16).to_le_bytes());
    buf.extend_from_slice(&sample_rate.to_le_bytes());
    buf.extend_from_slice(&byte_rate.to_le_bytes());
    buf.extend_from_slice(&block_align.to_le_bytes());
    buf.extend_from_slice(&16u16.to_le_bytes()); // bits per sample
                                                 // data subchunk
    buf.extend_from_slice(b"data");
    buf.extend_from_slice(&data_size.to_le_bytes());
    for &s in samples {
        let clipped = s.clamp(-1.0, 1.0);
        let i = (clipped * 32767.0).round() as i16;
        buf.extend_from_slice(&i.to_le_bytes());
    }

    let mut f = fs::File::create(path).map_err(|e| format!("create {}: {}", path, e))?;
    f.write_all(&buf)
        .map_err(|e| format!("write {}: {}", path, e))?;
    Ok(())
}

// ─────────────────────────────────────────────────────────────────────────────
// Stats helpers
// ─────────────────────────────────────────────────────────────────────────────

/// Compute (peak_abs, rms) over an f32 slice.
fn audio_stats(samples: &[f32]) -> (f32, f32) {
    if samples.is_empty() {
        return (0.0, 0.0);
    }
    let mut peak = 0.0f32;
    let mut sumsq = 0.0f64;
    for &s in samples {
        let a = s.abs();
        if a > peak {
            peak = a;
        }
        sumsq += (s as f64) * (s as f64);
    }
    let rms = (sumsq / samples.len() as f64).sqrt() as f32;
    (peak, rms)
}

// ─────────────────────────────────────────────────────────────────────────────
// CLI parsing
// ─────────────────────────────────────────────────────────────────────────────

/// Optional `--phonemes 12,5,7` flag for skipping the built-in G2P. Returns
/// `Ok(None)` if the flag isn't present, `Ok(Some(ids))` if parsed.
fn parse_phonemes_flag(args: &[String]) -> Result<Option<Vec<u32>>, String> {
    let iter = args.iter().enumerate();
    for (i, a) in iter {
        if a == "--phonemes" {
            let val = args
                .get(i + 1)
                .ok_or_else(|| "--phonemes requires a comma-separated list".to_string())?;
            let ids: Result<Vec<u32>, _> = val
                .split(',')
                .filter(|s| !s.is_empty())
                .map(|s| s.trim().parse::<u32>())
                .collect();
            return ids
                .map(Some)
                .map_err(|e| format!("--phonemes parse error: {}", e));
        }
    }
    Ok(None)
}

// ─────────────────────────────────────────────────────────────────────────────
// main
// ─────────────────────────────────────────────────────────────────────────────

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 5 {
        return Err(format!(
            "usage: {} <acoustic.knot> <vocoder.knot> <text> <out.wav> [--phonemes id1,id2,...] [--n-mels N]",
            args.first().map(String::as_str).unwrap_or("pneuma-tts-smoke")
        ));
    }
    let acoustic_path = &args[1];
    let vocoder_path = &args[2];
    let text = &args[3];
    let out_path = &args[4];

    let mut n_mels_override = None;
    let mut i = 5;
    while i < args.len() {
        if args[i] == "--n-mels" && i + 1 < args.len() {
            let val = args[i + 1].parse::<usize>().map_err(|e| e.to_string())?;
            n_mels_override = Some(val);
            i += 2;
        } else {
            i += 1;
        }
    }

    println!("============================================================");
    println!(" Pneuma TTS smoke");
    println!("   acoustic : {}", acoustic_path);
    println!("   vocoder  : {}", vocoder_path);
    println!("   text     : {:?}", text);
    println!("   out.wav  : {}", out_path);
    println!("============================================================");

    // 1. Load acoustic .knot + parse TtsConfig.
    println!("[1/7] mmap acoustic knot");
    let t0 = Instant::now();
    let acoustic_knot = KnotWeights::load(acoustic_path)?;
    let acoustic_backend: Arc<dyn WeightBackend> = Arc::clone(&acoustic_knot.backend);
    println!(
        "       ok ({} ms)  tensors={}",
        t0.elapsed().as_millis(),
        acoustic_knot.metadata.len()
    );

    println!("[2/7] parse TtsConfig");
    let acoustic_meta = read_knot_metadata(acoustic_path)?;
    let mut tts_cfg: TtsConfig = parse_tts_config(&acoustic_meta)?;
    if let Some(n) = n_mels_override {
        tts_cfg.n_mels = n;
    }
    let acoustic_codec: KnotCodec = parse_knot_codec(&acoustic_meta);
    println!(
        "       ok  enc={}L/{}d/{}h  inter={}  vocab={}  n_mels={}  speakers={}  codec={:?}",
        tts_cfg.encoder_layers,
        tts_cfg.hidden_dim,
        tts_cfg.encoder_heads,
        tts_cfg.encoder_intermediate_size,
        tts_cfg.vocab_size,
        tts_cfg.n_mels,
        tts_cfg.n_speakers,
        acoustic_codec,
    );

    // 2. Load vocoder .knot + parse VocoderConfig.
    println!("[3/7] mmap vocoder knot");
    let t1 = Instant::now();
    let vocoder_knot = KnotWeights::load(vocoder_path)?;
    let vocoder_backend: Arc<dyn WeightBackend> = Arc::clone(&vocoder_knot.backend);
    println!(
        "       ok ({} ms)  tensors={}",
        t1.elapsed().as_millis(),
        vocoder_knot.metadata.len()
    );

    println!("[4/7] parse VocoderConfig");
    let vocoder_meta = read_knot_metadata(vocoder_path)?;
    let mut voc_cfg: VocoderConfig = parse_vocoder_config(&vocoder_meta)?;
    if let Some(n) = n_mels_override {
        voc_cfg.n_mels = n;
    }
    let vocoder_codec: KnotCodec = parse_knot_codec(&vocoder_meta);
    println!(
        "       ok  init_ch={}  ups={:?}  resblock_k={:?}  sr={} Hz  codec={:?}",
        voc_cfg.initial_channels,
        voc_cfg.upsample_rates,
        voc_cfg.resblock_kernels,
        voc_cfg.sample_rate,
        vocoder_codec,
    );

    // 3. Phonemize text (or accept --phonemes override).
    println!("[5/7] phonemize");
    let phonemes: Vec<u32> = match parse_phonemes_flag(&args)? {
        Some(ids) => {
            println!("       --phonemes override: {} ids", ids.len());
            ids
        }
        None => {
            let ids = text_to_phoneme_ids_trivial(text);
            println!("       trivial G2P: {} ids", ids.len());
            ids
        }
    };
    if phonemes.is_empty() {
        return Err(
            "phonemizer produced 0 phonemes; cannot synthesize empty utterance".to_string(),
        );
    }
    // Bound-check against vocab so the acoustic model doesn't panic on a
    // mismatched inventory (helpful when the user supplies --phonemes).
    if let Some(&max_id) = phonemes.iter().max() {
        if (max_id as usize) >= tts_cfg.vocab_size {
            return Err(format!(
                "phoneme id {} >= acoustic vocab_size {} — inventory mismatch",
                max_id, tts_cfg.vocab_size,
            ));
        }
    }

    // 4. Build acoustic model + run forward → mel.
    println!("[6/7] acoustic forward");
    let t_build_a = Instant::now();
    let mut acoustic =
        TtsAcousticModel::with_codec(tts_cfg.clone(), acoustic_backend, acoustic_codec);
    let build_ms_a = t_build_a.elapsed().as_millis();
    let t_fwd_a = Instant::now();
    let mel = acoustic.forward(&phonemes);
    let fwd_ms_a = t_fwd_a.elapsed().as_millis();
    let mut mel = mel;
    // DEBUG: Sine wave mel to check vocoder modulation
    for i in 0..mel.len() {
        let f = (i as f32 * 0.1).sin() * 5.0;
        mel[i] = f;
    }
    let n_frames = mel.len() / tts_cfg.n_mels;
    // mel.fill(0.0); // original debug line
    let mel_min = mel.iter().cloned().fold(f32::INFINITY, f32::min);
    let mel_max = mel.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let mel_mean = mel.iter().sum::<f32>() / mel.len() as f32;
    println!(
        "       ok  build={}ms  forward={}ms  mel=({}, {})  range=[{:.3}, {:.3}] mean={:.3}",
        build_ms_a, fwd_ms_a, tts_cfg.n_mels, n_frames, mel_min, mel_max, mel_mean,
    );
    if !mel_min.is_finite() || !mel_max.is_finite() {
        return Err(format!(
            "acoustic produced non-finite mel (min={} max={})",
            mel_min, mel_max
        ));
    }

    // 5. Build vocoder + run forward → PCM.
    println!("[7/7] vocoder forward + WAV write");
    let t_build_v = Instant::now();
    let mut vocoder = HiFiGANVocoder::with_codec(voc_cfg.clone(), vocoder_backend, vocoder_codec);
    let build_ms_v = t_build_v.elapsed().as_millis();
    let t_fwd_v = Instant::now();
    let pcm: Vec<f32> = vocoder.forward(&mel);
    let fwd_ms_v = t_fwd_v.elapsed().as_millis();
    let (peak, rms) = audio_stats(&pcm);
    let duration_s = pcm.len() as f64 / voc_cfg.sample_rate as f64;
    println!(
        "       ok  build={}ms  forward={}ms  samples={}  duration={:.3}s  peak={:.4}  rms={:.4}",
        build_ms_v,
        fwd_ms_v,
        pcm.len(),
        duration_s,
        peak,
        rms,
    );
    if !peak.is_finite() || !rms.is_finite() {
        return Err(format!(
            "vocoder produced non-finite PCM (peak={} rms={})",
            peak, rms
        ));
    }

    // 6. Write WAV.
    write_wav_pcm16(out_path, &pcm, voc_cfg.sample_rate as u32)?;
    let wav_bytes = 44 + pcm.len() * 2;
    println!("       wrote {} bytes to {}", wav_bytes, out_path);

    println!("\n[done] pneuma TTS smoke succeeded");
    Ok(())
}

// ─────────────────────────────────────────────────────────────────────────────
// Tests
// ─────────────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn trivial_g2p_handles_quick_brown_fox() {
        let ids = text_to_phoneme_ids_trivial("the quick brown fox");
        assert!(!ids.is_empty(), "must produce phonemes");
        // 4 words → 3 inter-word pauses.
        let pauses = ids.iter().filter(|&&p| p == ID_PAUSE).count();
        assert_eq!(pauses, 3);
    }

    #[test]
    fn trivial_g2p_collapses_punctuation() {
        let a = text_to_phoneme_ids_trivial("hi, world!");
        let b = text_to_phoneme_ids_trivial("hi world");
        // Punctuation collapses to the same single boundary as whitespace.
        assert_eq!(a.iter().filter(|&&p| p == ID_PAUSE).count(), 1);
        assert_eq!(b.iter().filter(|&&p| p == ID_PAUSE).count(), 1);
    }

    #[test]
    fn trivial_g2p_empty_input_empty_output() {
        assert!(text_to_phoneme_ids_trivial("").is_empty());
        assert!(text_to_phoneme_ids_trivial("   ").is_empty());
        assert!(text_to_phoneme_ids_trivial(",.!?").is_empty());
    }

    #[test]
    fn phonemes_flag_parses_csv() {
        let args = vec![
            "binname".to_string(),
            "a".to_string(),
            "b".to_string(),
            "c".to_string(),
            "d".to_string(),
            "--phonemes".to_string(),
            "12,5,7,8".to_string(),
        ];
        let parsed = parse_phonemes_flag(&args).unwrap().unwrap();
        assert_eq!(parsed, vec![12, 5, 7, 8]);
    }

    #[test]
    fn phonemes_flag_absent_returns_none() {
        let args = vec!["binname".to_string(), "a".to_string()];
        assert!(parse_phonemes_flag(&args).unwrap().is_none());
    }

    #[test]
    fn audio_stats_basic() {
        let s = vec![0.0f32, 0.5, -0.5, 1.0, -1.0];
        let (peak, rms) = audio_stats(&s);
        assert!((peak - 1.0).abs() < 1e-6);
        // sqrt((0+0.25+0.25+1+1)/5) = sqrt(0.5)
        assert!((rms - 0.5f32.sqrt()).abs() < 1e-5);
    }

    #[test]
    fn wav_round_trips_size() {
        // Smoke test on the WAV writer — make sure header size math is right.
        let dir = std::env::temp_dir();
        let path = dir.join("pneuma-tts-smoke-wav-test.wav");
        let path_str = path.to_string_lossy().to_string();
        let samples: Vec<f32> = (0..1000).map(|i| (i as f32 / 1000.0).sin()).collect();
        write_wav_pcm16(&path_str, &samples, 22050).unwrap();
        let written = std::fs::metadata(&path).unwrap().len() as usize;
        assert_eq!(written, 44 + samples.len() * 2);
        let _ = std::fs::remove_file(&path);
    }
}
